*����������������� # me - this DAT
# par - the Par object that has changed
# val - the current value
# prev - the previous value
# 
# Make sure the corresponding toggle is enabled in the Parameter Execute DAT.

def onValueChange(par, prev):
	# use par.eval() to get current value

	if par.name == "Mouse3dactive":
		op('joystick1').bypass = not par

	return

def onPulse(par):

	if par.name == "Reset":
		parent.Camera.Reset();

	elif par.name == "Home":
		parent.Camera.Home(False);

	elif par.name == "Homeselected":
		parent.Camera.Home(True);

	elif par.name == "Frame":
		parent.Camera.Frame(False);

	elif par.name == "Frameselected":
		parent.Camera.Frame(True);

	elif par.name == "Sethomeangle":
		parent.Camera.SetHomeToCurrent();

	elif par.name == "Resethomeangle":
		parent.Camera.ResetHome();

	elif par.name == "Setpreset1":
		s, parent.Camera.parGroup.Presetangle1, parent.Camera.parGroup.Presetpos1 = parent.Camera.CameraTransform.decompose();

	elif par.name == "Setpreset2":
		s, parent.Camera.parGroup.Presetangle2, parent.Camera.parGroup.Presetpos2 = parent.Camera.CameraTransform.decompose();

	elif par.name == "Gotopreset1":
		parent.Camera.SetPosAndAngle(
			parent.Camera.parGroup.Presetpos1,
			parent.Camera.parGroup.Presetangle1 );

	elif par.name == "Gotopreset2":
		parent.Camera.SetPosAndAngle(
			parent.Camera.parGroup.Presetpos2,
			parent.Camera.parGroup.Presetangle2 );

	elif par.name == "Createcallbackdat":

		if not parent.Camera.par.Callbackdat.eval():
			dat = parent.Camera.parent().create(textDAT, 'camera_callbacks')
			dat.nodeY = parent.Camera.nodeY - 125
			dat.nodeX = parent.Camera.nodeX
			dat.dock = parent.Camera
			dat.text = parent().op('defaultCallbacks').text;
			parent.Camera.par.Callbackdat = dat.name
			#parent.Camera.par.Callbackdat.enable = True
			#parent.Camera.par.Callbackdat.readOnly = True

	return

